#include <stdio.h>
#include <stdlib.h>

#define MOD 1000000007LL

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        int *stack = (int*)malloc(N * sizeof(int));
        int top = -1;
        long long ans = 1;
        for (int i = N - 1; i >= 0; --i) {
            while (top >= 0 && a[stack[top]] >= a[i]) top--;
            long long fear = 1;
            if (top >= 0) fear = (long long)(stack[top] - i + 1);
            ans = (ans * fear) % MOD;
            stack[++top] = i;
        }
        printf("%lld\n", ans);
        free(a);
        free(stack);
    }
    return 0;
}

