const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(BigInt);
let idx = 0n;
function next() { return input[Number(idx++)]; }
if (input.length === 0) process.exit(0);
const T = Number(next());
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(next());
  const a = new Array(N);
  for (let i = 0; i < N; ++i) a[i] = Number(next()); // values fit in Number for comparisons
  const stack = [];
  let ans = 1n;
  for (let i = N - 1; i >= 0; --i) {
    while (stack.length && a[stack[stack.length - 1]] >= a[i]) stack.pop();
    let fear = 1n;
    if (stack.length) fear = BigInt(stack[stack.length - 1] - i + 1);
    ans = (ans * fear) % MOD;
    stack.push(i);
  }
  outputs.push(ans.toString());
}
console.log(outputs.join('\n'));

